script:
frappe.ui.form.on('Student Applicant', {
    refresh: function(frm) {
        frm.set_intro('');

        if (frm.doc.student_email_id) {
            frm.set_intro(
                '<b>Student Email:</b> ' + frm.doc.student_email_id,
                'blue'
            );
            frm.set_df_property('student_email_id', 'read_only', 1);
            frm.refresh_field('student_email_id');
        } else if (!frm.is_new()) {
            frm.set_intro('Generating student email...', 'yellow');
            frappe.call({
                method: 'edvronix.edvronix_app.api.student_applicant.generate_email_now',
                args: { applicant_name: frm.doc.name },
                callback: function(r) {
                    if (r.message) {
                        frm.doc.student_email_id = r.message;
                        frm.set_intro(
                            '<b>Student Email:</b> ' + r.message,
                            'blue'
                        );
                        frm.set_df_property('student_email_id', 'read_only', 1);
                        frm.refresh_field('student_email_id');
                    } else {
                        frm.set_intro('Could not auto-generate email. Please fill it manually.', 'red');
                    }
                }
            });
        }
    }
});

frappe.listview_settings['Student'] = frappe.listview_settings['Student'] || {};

frappe.listview_settings['Student'].add_fields = ['reason_for_leaving'];

frappe.listview_settings['Student'].get_indicator = function(doc) {
    if (doc.enabled) {
        return [__('Active'), 'green', 'enabled,=,1'];
    } else if (doc.reason_for_leaving === 'Graduated') {
        return [__('Graduated'), 'purple', 'enabled,=,0|reason_for_leaving,=,Graduated'];
    } else {
        return [__('Disabled'), 'red', 'enabled,=,0'];
    }
};

frappe.ui.form.on('Student', {
    refresh: function(frm) {
        if (!frm.doc.enabled && frm.doc.reason_for_leaving === 'Graduated') {
            frm.set_df_property('enabled', 'read_only', 1);
            frm.refresh_field('enabled');

            frappe.db.get_list('Graduation Student Detail', {
                filters: { student: frm.doc.name },
                fields: ['parent'],
                limit: 1
            }).then(function(rows) {
                let doc_link = '';
                if (rows && rows.length) {
                    let grad_name = rows[0].parent;
                    doc_link = ' <a href="/app/student-graduation/' + encodeURIComponent(grad_name) + '"><b>' + grad_name + '</b></a>';
                }
                frm.set_intro(
                    'This student has <b>Graduated</b>' +
                    (frm.doc.date_of_leaving ? ' on ' + frappe.datetime.str_to_user(frm.doc.date_of_leaving) : '') + '.' +
                    (frm.doc.leaving_certificate_number ? ' Certificate No: <b>' + frm.doc.leaving_certificate_number + '</b>' : '') +
                    '<br><small>To restore this student, cancel the graduation document:' + doc_link + '</small>',
                    'green'
                );
            });
        }

        if (!frm.is_new() && frm.doc.enabled) {
            frm.add_custom_button(__('Graduate Student'), function() {
                frappe.prompt([
                    {
                        fieldname: 'graduation_date',
                        fieldtype: 'Date',
                        label: __('Graduation Date'),
                        reqd: 1,
                        default: frappe.datetime.get_today()
                    },
                    {
                        fieldname: 'certificate_number',
                        fieldtype: 'Data',
                        label: __('Certificate Number (optional)')
                    },
                    {
                        fieldname: 'notes',
                        fieldtype: 'Small Text',
                        label: __('Notes (optional)')
                    }
                ],
                function(values) {
                    frappe.call({
                        method: 'edvronix.edvronix_app.doctype.student_graduation.student_graduation.graduate_single_student',
                        args: {
                            student: frm.doc.name,
                            graduation_date: values.graduation_date,
                            certificate_number: values.certificate_number || '',
                            notes: values.notes || ''
                        },
                        freeze: true,
                        freeze_message: __('Graduating student...'),
                        callback: function(r) {
                            if (r.message && r.message.success) {
                                frappe.show_alert({ message: __('Student graduated successfully.'), indicator: 'green' });
                                frm.reload_doc();
                            }
                        }
                    });
                },
                __('Graduate Student'),
                __('Confirm')
                );
            }, __('Actions'));
        }
    }
});

frappe.ui.form.on('Exam Setup', {
    refresh: function(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button(__('Open Exam Setup Tool'), function() {
                frappe._es_pending_nav_exam = frm.doc.exam_name || frm.doc.name;
                frappe.set_route('exam-tool');
            }, __('Actions'));

            render_exam_section_progress(frm);
        } else {
            frm.fields_dict.section_progress_html.$wrapper.html(
                '<p style="color:#8d99a6;font-size:13px">Save the form first, then create plans to see section progress.</p>'
            );
        }
    }
});

function render_exam_section_progress(frm) {
    var $w = frm.fields_dict.section_progress_html.$wrapper;
    $w.html('<p style="color:#8d99a6;font-size:13px">Loading…</p>');
    var exam_name = frm.doc.exam_name || frm.doc.name;

    frappe.call({
        method: 'edvronix.edvronix_app.page.exam_tool.exam_tool.get_section_progress',
        args: { exam_name: exam_name },
        callback: function(r) {
            var rows = r.message || [];
            if (!rows.length) {
                $w.html(
                    '<div style="padding:14px 16px;background:#fff8e1;border:1px solid #ffe082;border-radius:6px">'
                    + '<p style="font-size:13px;color:#6d4c41;margin:0 0 6px">No Assessment Plans created yet for <strong>' + frappe.utils.escape_html(exam_name) + '</strong>.</p>'
                    + '<p style="font-size:11px;color:#8d99a6;margin:0 0 10px">Plans are created from the Exam Setup Tool — select sections and click <em>Create Exam Plans</em>.</p>'
                    + '<button class="btn btn-sm btn-primary es-open-tool-btn" style="font-size:12px">'
                    + '<i class="fa fa-pencil"></i> Open Exam Setup Tool</button>'
                    + '</div>'
                );
                $w.find('.es-open-tool-btn').on('click', function() {
                    frappe._es_pending_nav_exam = exam_name;
                    frappe.set_route('exam-tool');
                });
                return;
            }

            var STATUS_COLOR = { 'Pending': '#dc3545', 'Marks Entered': '#e2a03f', 'Result Generated': '#2e7d32' };
            var STATUS_BG    = { 'Pending': '#fff5f5', 'Marks Entered': '#fff8e1', 'Result Generated': '#f1f8f1' };

            var tbody = rows.map(function(row) {
                var color = STATUS_COLOR[row.status] || '#6c757d';
                var bg    = STATUS_BG[row.status]    || '#f8f9fa';
                var pct   = row.total_students ? Math.round(row.submitted_results / row.total_students * 100) : 0;
                var bar   = '<div style="background:#e9ecef;border-radius:3px;height:4px;margin-top:3px">'
                    + '<div style="background:' + color + ';width:' + pct + '%;height:4px;border-radius:3px"></div></div>';

                return '<tr style="background:' + bg + '">'
                    + '<td style="padding:8px 12px;font-weight:500">' + frappe.utils.escape_html(row.section) + '</td>'
                    + '<td style="padding:8px 12px;text-align:center">' + row.submitted_results + ' / ' + row.total_students + bar + '</td>'
                    + '<td style="padding:8px 12px;text-align:center">'
                    +   '<span style="color:' + color + ';font-weight:600;font-size:12px">'
                    +   frappe.utils.escape_html(row.status) + '</span></td>'
                    + '<td style="padding:8px 12px;text-align:center">'
                    +   '<a class="btn btn-xs btn-primary es-enter-marks" '
                    +      'data-exam="' + frappe.utils.escape_html(exam_name) + '" '
                    +      'data-section="' + frappe.utils.escape_html(row.section) + '" '
                    +      'style="font-size:11px">Enter Marks →</a></td>'
                    + '</tr>';
            }).join('');

            $w.html(
                '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">'
                + '<span style="font-size:12px;color:#8d99a6">' + rows.length + ' section(s)</span>'
                + '<button class="btn btn-xs btn-default es-refresh-progress" style="font-size:11px">'
                + '<i class="fa fa-refresh"></i> Refresh</button></div>'
                + '<table class="table table-bordered" style="font-size:13px;margin:0">'
                + '<thead style="background:#f5f7fa"><tr>'
                + '<th style="padding:8px 12px">Section</th>'
                + '<th style="padding:8px 12px;width:120px;text-align:center">Students</th>'
                + '<th style="padding:8px 12px;width:170px;text-align:center">Status</th>'
                + '<th style="padding:8px 12px;width:130px;text-align:center">Action</th>'
                + '</tr></thead><tbody>' + tbody + '</tbody></table>'
            );

            $w.find('.es-refresh-progress').on('click', function() {
                render_exam_section_progress(frm);
            });

            $w.find('.es-enter-marks').on('click', function(e) {
                e.preventDefault();
                var exam = $(this).data('exam');
                var section = $(this).data('section');
                frappe._em_pending_exam = exam;
                frappe._em_pending_section = section;
                frappe.set_route('exam-marks');
            });
        }
    });
}
